// // This module implements a 4-bit selector with XOR for C=2, B for C=1, and A otherwise.
module top_module(
    input [3:0] A,
    input [3:0] B,
    input [1:0] C,
    output reg [3:0] out
);always @(*) begin
    case(C)
        2: out = A ^ B;
        1: out = B;
        default: out = A;
    endcase
end

endmodule
